package phonedata_java;

import org.junit.jupiter.api.Test;

import cn.lalaki.phone.location.PhoneLocation;
import cn.lalaki.phone.location.PhoneLocation.PhoneInfo;

import static org.junit.jupiter.api.Assertions.*;

import java.io.IOException;

class LibraryTest {
    @Test
    void someLibraryMethodReturnsTrue() {
        PhoneInfo phoneInfo = null;
        try {
            phoneInfo = PhoneLocation.queryPhoneInfo("13017199838");
        } catch (IOException e) {
            e.fillInStackTrace();
        }
        assertNotNull(phoneInfo);
        System.out.printf("%s, %s, %s, %s, %s, %s%n", phoneInfo.province(), phoneInfo.city(),
                phoneInfo.zipCode(), phoneInfo.areaCode(), phoneInfo.carrier(), phoneInfo.version());
    }
}
